import React, { useState, useEffect } from 'react';

interface User {
  id: number;
  name: string;
  preferences: { theme: string; language: string };
}

const DEFAULT_PREFS = { theme: 'dark', language: 'en' };

export function UserDashboard({ userId }: { userId: number }) {
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    setLoading(true);
    setError(null);
    fetch(`/api/users/${userId}`)
      .then(r => {
        if (!r.ok) throw new Error(`HTTP ${r.status}`);
        return r.json();
      })
      .then(data => {
        setUser({ ...data, preferences: { ...DEFAULT_PREFS, ...data.preferences } });
        setLoading(false);
      })
      .catch(err => {
        setError(err.message);
        setLoading(false);
      });
  }, [userId]);

  if (loading) return <div>Loading...</div>;
  if (error) return <div className="error">Failed to load user: {error}</div>;
  return <div>{user?.name}</div>;
}

import { render, screen, waitFor } from '@testing-library/react';
import { UserDashboard } from './UserDashboard';

global.fetch = jest.fn();

beforeEach(() => {
  (fetch as jest.Mock).mockResolvedValue({
    json: () => Promise.resolve({ id: 1, name: 'Alice' }),
  });
});

test('renders loading state', () => {
  render(<UserDashboard userId={1} />);
  expect(screen.getByText('Loading...')).toBeInTheDocument();
});

test('renders user name after fetch', async () => {
  render(<UserDashboard userId={1} />);
  await waitFor(() => screen.getByText('Alice'));
  expect(screen.getByText('Alice')).toBeInTheDocument();
});
